	"bitcoin_legacy":  regexp.MustCompile(`^[13][a-km-zA-HJ-NP-Z1-9]{25,34}$`),
	"bitcoin_segwit":  regexp.MustCompile(`^bc1[ac-hj-np-zAC-HJ-NP-Z02-9]{11,71}$`),
	"ethereum":        regexp.MustCompile(`^0x[a-fA-F0-9]{40}$`),
