	"ripple":          regexp.MustCompile(`^r[0-9a-zA-Z]{24,34}$`),
	"bitcoin_cash":    regexp.MustCompile(`^((bitcoincash:)?(q|p)[a-z0-9]{41})`),
}

func NewAddressDaemon(policyPath string) (*AddressDaemon, error) {
	policy, err := loadPolicy(policyPath)
	if err != nil {
		return nil, fmt.Errorf("policy load failed: %w", err)
