function parseRequestBody(requestBody) {
  if (!requestBody || !requestBody.raw) return null;

  try {
    // Decode the raw body (assuming UTF-8)
    const decoder = new TextDecoder("utf-8");
    const bodyString = decoder.decode(requestBody.raw);

    // Attempt to parse as JSON
    return JSON.parse(bodyString);
  } catch (e) {
    // If not JSON, it might be FormData (application/x-www-form-urlencoded)
    const params = new URLSearchParams(requestBody.raw);
    return Object.fromEntries(params.entries());
